function maxCompatibilitySum(students, mentors) {
    students.sort((a, b) => a.join("") - b.join(""));
    mentors.sort((a, b) => a.join("") - b.join(""));
    return helper(students, mentors, 0);
}

function helper(students, mentors, idx) {
    if (idx == students.length) {
        return 0;
    }
    let ans = 0;
    for (let i = 0; i < mentors.length; i++) {
        if (mentors[i] !== null) {
            let count = 0;
            let temp = mentors[i];
            for (let j = 0; j < students[idx].length; j++) {
                if (students[idx][j] === temp[j]) {
                    count++;
                }
            }
            mentors[i] = null;
            ans = Math.max(ans, count + helper(students, mentors, idx + 1));
            mentors[i] = temp;
        }
    }
    return ans;
}
```

    The algorithm first sorts both the students and the mentors arrays. Then, it finds all possible pairings between students and mentors. For each pairing, it calculates the compatibility score by counting the number of matching answers. The sum of the compatibility scores for each pairing is then calculated, and the maximum sum is returned as the final result.

