import java.util.Arrays;

public int maxCompatibilitySum(int[][] students, int[][] mentors) {
    Arrays.sort(students, (a, b) -> Arrays.toString(a).compareTo(Arrays.toString(b)));
    Arrays.sort(mentors, (a, b) -> Arrays.toString(a).compareTo(Arrays.toString(b)));
    return helper(students, mentors, 0);
}

private int helper(int[][] students, int[][] mentors, int idx) {
    if (idx == students.length)
        return 0;
    int ans = 0;
    for (int i = 0; i < mentors.length; i++) {
        if (mentors[i] != null) {
            int[] temp = mentors[i];
            int count = 0;
            for (int j = 0; j < students[idx].length; j++) {
                if (students[idx][j] == temp[j])
                    count++;
            }
            mentors[i] = null;
            ans = Math.max(ans, count + helper(students, mentors, idx + 1));
            mentors[i] = temp;
        }
    }
    return ans;
}
```

